import { MPFacil } from './src/index.js';

if (!process.env.MP_ACCESS_TOKEN) {
  console.log('Defina MP_ACCESS_TOKEN antes de rodar este teste.');
  process.exit(1);
}

const mp = new MPFacil({
  apiKey: process.env.MP_ACCESS_TOKEN,
  sandbox: false,
  autoResumeLoops: false
});

const paymentId = '';

mp.on('pago', (pagamento) => {
  console.log('Pedido liberado:', pagamento.referencia);
  console.log('Usuario:', pagamento.metadados.idUser);
});

mp.on('recusado', (pagamento) => {
  console.log('Pagamento falhou:', pagamento.statusDetalhado);
});

mp.on('pendente', (pagamento) => {
  console.log('Ainda esperando:', pagamento.id);
});

mp.on('erro', (erro) => {
  console.log('Erro no acompanhamento:', erro);
});

const cobranca = await mp.criarCobranca({
  produto: 'clube do cafe - plano mensal',
  id: 'cafe',
  preco: 0.20,
  metadados: {
    idUser: 'jxd12dd3'
  },
  urlSucesso: 'http://localhost:3000/pagamento/volta',
  urlFalha: 'http://localhost:3000/pagamento/volta',
  urlPendente: 'http://localhost:3000/pagamento/volta'
});

if (!cobranca.ok) {
  console.log('Erro ao criar cobranca:', cobranca);
  process.exitCode = 1;
} else {
  console.log('Cobranca criada com sucesso!');
  console.log('ID da preferencia:', cobranca.dados.id);
  console.log('Envie o cliente para:', cobranca.dados.link);
}

if (cobranca.ok && !paymentId) {
  console.log('');
  console.log('O loop ainda nao iniciou porque paymentId esta vazio.');
  console.log('Esse ID nao e o ID da preferencia. Ele aparece como payment_id/collection_id na URL de retorno ou no webhook depois do checkout.');
  console.log("Quando tiver esse ID, coloque no topo do arquivo: const paymentId = 'ID_REAL_DO_PAGAMENTO';");
}

if (cobranca.ok && paymentId) {
  const pagamento = await mp.consultarCobranca(paymentId);

  if (!pagamento.ok) {
    console.log('Erro ao consultar pagamento:', pagamento);
  } else {
    console.log('Status inicial do pagamento:', pagamento.dados.situacao);
  }

  const loop = await mp.acompanharCobranca(paymentId, {
    intervaloMs: 5000
  });

  if (!loop.ok) {
    console.log('Erro ao iniciar loop:', loop);
    process.exitCode = 1;
  } else {
    console.log('Loop iniciado para pagamento:', paymentId);
    console.log('Memoria do loop:', loop.dados.arquivo);
  }
}
